// openai-codex image backend. Used as the modal portrait in the horse
// detail view (size='xl'); pixel-art from /assets/horses/index.js stays
// in the lineup/grid.
//
// Naming: {breed_prefix}_{lifeStage}_{mood}.png
// Breed prefixes match horse.js BREED_POOL.prefix values:
//   quarter_horse=qh, appaloosa=appy, paint_horse=paint,
//   arabian=arab, thoroughbred=tb, andalusian=andy
//
// Lookup follows the same four-tier fallback chain as the pixel-art set:
//   1. exact: breed + lifeStage + mood
//   2. breed + lifeStage + 'calm' (any-mood fallback)
//   3. breed + lifeStage (any-mood fallback)
//   4. any breed + lifeStage + mood (any-breed fallback)

const FALLBACK_LIFE_STAGE = 'campaigner';
const FALLBACK_BREED = 'quarter_horse';

// Breed id → file prefix. Must match the prefix in BREED_POOL.
const BREED_PREFIX = {
  quarter_horse: 'qh',
  appaloosa: 'appy',
  paint_horse: 'paint',
  arabian: 'arab',
  thoroughbred: 'tb',
  andalusian: 'andy',
};

// Reverse map: prefix → breed id (for the any-breed fallback).
const PREFIX_TO_BREED = Object.fromEntries(
  Object.entries(BREED_PREFIX).map(([k, v]) => [v, k])
);

